/**
 * @param {string} s
 * @return {string}
 */
function solve(s) {
    const vowels = new Set(['a', 'e', 'i', 'o', 'u']);
    const n = s.length;

    // 1. Calculate frequency and track first appearance
    const counts = {};
    const firstIndices = {};

    for (let i = 0; i < n; i++) {
        const char = s[i];
        if (vowels.has(char)) {
            // Count frequency
            counts[char] = (counts[char] || 0) + 1;

            // Track first appearance index
            if (firstIndices[char] === undefined) {
                firstIndices[char] = i;
            }
        }
    }

    // Get unique vowels present in s
    const presentVowels = Object.keys(counts);

    // 2. Sort the unique vowels based on criteria
    // Primary: Frequency (Non-increasing -> descending)
    // Secondary: First Appearance Index (Ascending)
    presentVowels.sort((v1, v2) => {
        const freq1 = counts[v1];
        const freq2 = counts[v2];

        // Compare frequencies (descending)
        if (freq1 !== freq2) {
            return freq2 - freq1;
        }
        // Frequencies are equal, compare first index (ascending)
        return firstIndices[v1] - firstIndices[v2];
    });

    // 3. Build the new sequence of vowels (V_new)
    let newVowelSequence = "";
    for (const vowel of presentVowels) {
        const count = counts[vowel];
        newVowelSequence += vowel.repeat(count);
    }

    // 4. Reconstruct the string
    const result = Array(n);
    let vowelSequenceIndex = 0;

    for (let i = 0; i < n; i++) {
        const char = s[i];
        if (vowels.has(char)) {
            // Replace vowel with the next vowel from the sorted sequence
            result[i] = newVowelSequence[vowelSequenceIndex];
            vowelSequenceIndex++;
        } else {
            // Consonants remain unchanged
            result[i] = char;
        }
    }

    return result.join('');
}

